module RefModule(
    input clk,
    input signal,
    output reg pulse
    );

    reg signal_d;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        signal_d <= signal;
        pulse <= signal & ~signal_d;
    end
endmodule
